package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testLineItemConstructorAndGetters() throws Exception {
    String name = "Test Item";
    int quantity = 5;
    long priceInMicros = 123456789L;
    String currencyCode = "USD";

    // Directly use the class without reflection since it's available in the same package
    LineItem lineItem = new LineItem(name, quantity, priceInMicros, currencyCode);

    assertEquals(name, lineItem.getName());
    assertEquals(quantity, lineItem.getQuantity());
    assertEquals(priceInMicros, lineItem.getPriceInMicros());
    assertEquals(currencyCode, lineItem.getCurrencyCode());
  }

  @Test
  void testToStringNotNull() throws Exception {
    LineItem lineItem = new LineItem("Item", 1, 1000L, "EUR");

    String toStringResult = lineItem.toString();

    assertNotNull(toStringResult);
    assertTrue(toStringResult.contains("Item"));
  }
}
